import{_ as a,c as r,o as i,ag as t}from"./chunks/framework.piE7uVCg.js";const o="/assets/sigmalite01.Cj6QXbep.png",l="/assets/sigmalite02.BULkJyhn.png",c="/assets/sigmalite03.DjchtP6z.png",s="/assets/sigmalite05.1WJ9bOst.png",n="/assets/sigmalite06.CqR5Q_LK.png",u="/assets/sigmalite05.1WJ9bOst.png",d="/assets/sigmalite08.BKncYEe9.png",q=JSON.parse('{"title":"Morpho Access","description":"","frontmatter":{},"headers":[],"relativePath":"securite/access/morphoaccess.md","filePath":"securite/access/morphoaccess.md"}'),g={name:"securite/access/morphoaccess.md"};function m(h,e,p,f,_,b){return i(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="morpho-access" tabindex="-1"><a href="./readme.html">Morpho Access</a> <a class="header-anchor" href="#morpho-access" aria-label="Permalink to &quot;[Morpho Access](readme.md)&quot;">​</a></h1><h2 id="lecteur-sigma-lite" tabindex="-1">Lecteur Sigma Lite <a class="header-anchor" href="#lecteur-sigma-lite" aria-label="Permalink to &quot;Lecteur Sigma Lite&quot;">​</a></h2><p>Le lecteur sigma lite dispose d&#39;un lecteur de badge et d&#39;un capteur d&#39;empreintes.</p><h2 id="activation-du-lecteur" tabindex="-1">Activation du lecteur <a class="header-anchor" href="#activation-du-lecteur" aria-label="Permalink to &quot;Activation du lecteur&quot;">​</a></h2><ol><li>Alimenter le lecteur en POE</li><li>Lancer le logiciel <a href="https://www.biotime-technology.com/wxcvbn/MBTB_4.6.13.zip" target="_blank" rel="noreferrer">MBTB</a>.</li><li>Lancer le logiciel MBTB</li><li>Sasir l&#39;adresse IP par défaut <img src="'+o+'" alt="sigma01"></li><li>Cocher <code>Usine</code> dans la section <code>Configuration TLS</code> puis <code>Connexion</code> pour activer le lecteur. Si cela ne marche pas il faut déconnecter le lecteur et le rebrancher</li><li>Si c&#39;est appuyez sur <code>Fichier</code>&gt; <code>Déconencter le termnal courant</code></li><li>Ensuite cocher <code>Aucune</code> puis <code>Connexion</code>. <img src="'+l+'" alt="sigma01"></li><li>Activer le serveur web <ol><li>Rechercher <code>server</code> puis mettre <code>comm_channels._state.web_server</code></li><li>mettre local à 1</li><li><img src="'+c+'" alt="sigma01"></li></ol></li></ol><h2 id="se-connecter-a-l-interface-web" tabindex="-1">Se connecter à l&#39;interface web <a class="header-anchor" href="#se-connecter-a-l-interface-web" aria-label="Permalink to &quot;Se connecter à l&#39;interface web&quot;">​</a></h2><ol><li>Se connecter sur l&#39;adresse IP 192.168.1.10 via un navigateur</li><li>Les identifiants sont Admin/12345</li></ol><h2 id="configuration-weigand" tabindex="-1">Configuration weigand <a class="header-anchor" href="#configuration-weigand" aria-label="Permalink to &quot;Configuration weigand&quot;">​</a></h2><ol><li>Aller au menu <code>Paramètres du terminal</code>&gt;<code>Weigand</code></li><li>Choisir le format de badges par exemple le 26 bits</li><li>Activer les sorties weigand <img src="'+s+'" alt="alt text"></li></ol><h2 id="configurer-les-evenements" tabindex="-1">Configurer les évènements <a class="header-anchor" href="#configurer-les-evenements" aria-label="Permalink to &quot;Configurer les évènements&quot;">​</a></h2><ol><li>Aller sur <code>Configurations de controle</code>&gt;<code>Evenement</code></li><li>Choisir les évènements à envoyer au controlleur tel que les <code>Evénement succès de contrôle utilisateur</code></li></ol><h2 id="configurer-le-type-de-carte" tabindex="-1">Configurer le type de carte <a class="header-anchor" href="#configurer-le-type-de-carte" aria-label="Permalink to &quot;Configurer le type de carte&quot;">​</a></h2><ol><li>Aller sur <code>Configurations de controle</code>&gt;<code>carte sans contact</code></li><li>dans la partie <code>Encoder le profil</code> et <code>Lire le profil</code></li></ol><h2 id="sauvegarder-et-charger-la-configuration" tabindex="-1">Sauvegarder et charger la configuration <a class="header-anchor" href="#sauvegarder-et-charger-la-configuration" aria-label="Permalink to &quot;Sauvegarder et charger la configuration&quot;">​</a></h2><p>La configuration le prend pas compte la base de donnée d&#39;utilisateurs.</p><ol><li><code>Sauvegarder</code> pour enregistrer la configuration locale</li><li>Charger pour charger une configuration</li><li><img src="'+n+'" alt="alt text"></li></ol><h2 id="logiciel" tabindex="-1">Logiciel <a class="header-anchor" href="#logiciel" aria-label="Permalink to &quot;Logiciel&quot;">​</a></h2><p>Il faut le logiciel morpho manager pour pouvoir gérer facilement les utilisateurs.</p><h2 id="ajouter-un-utilisateur" tabindex="-1">Ajouter un utilisateur <a class="header-anchor" href="#ajouter-un-utilisateur" aria-label="Permalink to &quot;Ajouter un utilisateur&quot;">​</a></h2><p>Il faut utiliser les numéros de cartes générés sur winpak <img src="'+u+'" alt="alt text"><img src="'+d+'" alt="alt text"></p>',20)])])}const x=a(g,[["render",m]]);export{q as __pageData,x as default};
